    suspend fun getDeviceStatus(deviceIp: String): DeviceStatus {
        val url = "http://$deviceIp/api/status"
        val response = get(url)
        
        if (!response.isSuccessful) {
            throw IOException("Failed to get device status: ${response.code}")
        }

        val body = response.body?.string() ?: throw IOException("Empty response body")
        val json = JSONObject(body)
        
        return DeviceStatus(
            deviceId = json.optString("deviceId", ""),
            online = json.optBoolean("online", false),
            temperature = json.optDouble("temperature", 0.0),
            humidity = json.optDouble("humidity", 0.0),
            lastUpdate = json.optLong("lastUpdate", 0L)
        )
    }

    suspend fun controlDevice(deviceIp: String, command: String, value: Any): Boolean {
        val url = "http://$deviceIp/api/control"
        val json = JSONObject().apply {
