    suspend fun syncWithCloud(deviceData: DeviceData, authToken: String): CloudResponse {
        val url = "$CLOUD_BASE_URL/devices/sync"
        val headers = mapOf(
            "Authorization" to "Bearer $authToken",
            "Content-Type" to "application/json"
        )
        
        val json = JSONObject().apply {
            put("deviceId", deviceData.deviceId)
            put("status", deviceData.status)
            put("data", JSONObject(deviceData.data))
            put("timestamp", System.currentTimeMillis())
        }
        
        val response = post(url, json.toString(), headers)
        
        if (!response.isSuccessful) {
            throw IOException("Cloud sync failed: ${response.code}")
        }

        val body = response.body?.string() ?: throw IOException("Empty response body")
        val responseJson = JSONObject(body)
        
        return CloudResponse(
            success = responseJson.optBoolean("success", false),
            message = responseJson.optString("message", ""),
            data = responseJson.optJSONObject("data")?.toString()
        )
    }

    suspend fun getCloudDevices(authToken: String): List<CloudDevice> {
        val url = "$CLOUD_BASE_URL/devices"
        val headers = mapOf("Authorization" to "Bearer $authToken")
        
        val response = get(url, headers)
        
        if (!response.isSuccessful) {
            throw IOException("Failed to get devices: ${response.code}")
        }

        val body = response.body?.string() ?: throw IOException("Empty response body")
        val json = JSONObject(body)
        val devicesArray = json.optJSONArray("devices") ?: return emptyList()
        
        val devices = mutableListOf<CloudDevice>()
        for (i in 0 until devicesArray.length()) {
            val deviceJson = devicesArray.getJSONObject(i)
            devices.add(
                CloudDevice(
                    id = deviceJson.optString("id", ""),
                    name = deviceJson.optString("name", ""),
                    type = deviceJson.optString("type", ""),
                    localIp = deviceJson.optString("localIp", null),
                    online = deviceJson.optBoolean("online", false)
                )
            )
        }
        
        return devices
    }

    suspend fun registerDevice(deviceIp: String, authToken: String): String {
        val deviceInfoResponse = get("http://$deviceIp/api/info")
        
        if (!deviceInfoResponse.isSuccessful) {
            throw IOException("Failed to get device info: ${deviceInfoResponse.code}")
