        val deviceInfoBody = deviceInfoResponse.body?.string() ?: throw IOException("Empty response body")
        val deviceInfo = JSONObject(deviceInfoBody)
        
        val url = "$CLOUD_BASE_URL/devices/register"
        val headers = mapOf(
            "Authorization" to "Bearer $authToken",
            "Content-Type" to "application/json"
